 1	import * as React from 'react';
 2	import {
 3	  FormGroup,
 4	  FormHelperText,
 5	  HelperText,
 6	  HelperTextItem,
 7	  TextArea,
 8	} from '@patternfly/react-core';
 9	import { useField } from 'formik';
10	import { FieldProps } from '../pipelines-details/multi-column-field/types';
11	import { getFieldId } from '../pipelines-details/multi-column-field/utils';
12	
13	export interface TextAreaProps extends FieldProps {
14	  placeholder?: string;
15	  onChange?: (event) => void;
16	  onBlur?: (event) => void;
17	  rows?: number;
18	  resizeOrientation?: 'vertical' | 'horizontal' | 'both';
19	}
20	
21	const TextAreaField = (
22	  { label, helpText, required, onChange, ...props },
23	  ref,
24	) => {
25	  const [field, { touched, error }] = useField(props.name);
26	  const fieldId = getFieldId(props.name, 'input');
27	  const isValid = !(touched && error);
28	  const errorMessage = !isValid ? error : '';
29	  return (
30	    <FormGroup fieldId={fieldId} label={label} isRequired={required}>
31	      <TextArea
32	        {...field}
33	        {...props}
34	        ref={ref}
35	        id={fieldId}
36	        style={{ resize: 'vertical' }}
37	        validated={isValid ? 'default' : 'error'}
38	        isRequired={required}
39	        aria-describedby={helpText ? `${fieldId}-helper` : undefined}
40	        onChange={(event, value) => {
41	          onChange && onChange(value);
42	          field.onChange(event);
43	        }}
44	      />
45	      <FormHelperText>
46	        <HelperText>
47	          <HelperTextItem variant={!isValid ? 'error' : 'default'}>
48	            {!isValid ? errorMessage : helpText}
49	          </HelperTextItem>
50	        </HelperText>
51	      </FormHelperText>
52	    </FormGroup>
53	  );
54	};
55	
56	export default React.forwardRef(TextAreaField);

